import React, { useState, useEffect, useCallback } from 'react';
import axios from 'axios';
import Timer from './Timer';

const QuizPage = ({ quizId, teamInfo, onSubmit, onTimeout }) => {
  const [questions, setQuestions] = useState([]);
  const [currentIndex, setCurrentIndex] = useState(0);
  const [answers, setAnswers] = useState({});
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');
  const [tabSwitchCount, setTabSwitchCount] = useState(0);
  const [submitting, setSubmitting] = useState(false);

  // Enhanced anti-screenshot and copy protection
  useEffect(() => {
    // Disable all possible copying methods
    const disableAll = (e) => {
      e.preventDefault();
      e.stopPropagation();
      return false;
    };

    // Disable print screen (partial protection)
    const disablePrintScreen = (e) => {
      if (e.key === 'PrintScreen') {
        e.preventDefault();
        return false;
      }
    };

    // Block common screenshot shortcuts
    const disableScreenshotKeys = (e) => {
      // Windows: Windows + Shift + S, Windows + PrtScn
      // Mac: Cmd + Shift + 3, Cmd + Shift + 4, Cmd + Shift + 5
      if (
        (e.metaKey && e.shiftKey && (e.key === '3' || e.key === '4' || e.key === '5')) ||
        (e.ctrlKey && e.shiftKey && e.key === 's') ||
        e.key === 'PrintScreen'
      ) {
        e.preventDefault();
        return false;
      }
    };

    // Disable right click
    document.addEventListener('contextmenu', disableAll);

    // Disable copy/cut/paste
    document.addEventListener('copy', disableAll);
    document.addEventListener('cut', disableAll);
    document.addEventListener('paste', disableAll);

    // Disable select all and other key combinations
    document.addEventListener('keydown', (e) => {
      // Disable Ctrl+A, Ctrl+C, Ctrl+V, Ctrl+X, Ctrl+S, Ctrl+P
      if (
        (e.ctrlKey || e.metaKey) && 
        (e.key === 'a' || e.key === 'c' || e.key === 'v' || e.key === 'x' || e.key === 's' || e.key === 'p')
      ) {
        e.preventDefault();
        return false;
      }
      // Disable F12, Ctrl+Shift+I, Ctrl+Shift+J, Ctrl+U
      if (
        e.key === 'F12' ||
        (e.ctrlKey && e.shiftKey && (e.key === 'I' || e.key === 'J')) ||
        (e.ctrlKey && e.key === 'u')
      ) {
        e.preventDefault();
        return false;
      }
      // Disable screenshot shortcuts
      disableScreenshotKeys(e);
    });

    // Disable text selection
    document.addEventListener('selectstart', disableAll);

    // Disable drag and drop
    document.addEventListener('dragstart', disableAll);

    // Add CSS to prevent selection and image dragging
    const style = document.createElement('style');
    style.innerHTML = `
      * {
        -webkit-user-select: none !important;
        -moz-user-select: none !important;
        -ms-user-select: none !important;
        user-select: none !important;
        -webkit-touch-callout: none !important;
        -webkit-user-drag: none !important;
        -khtml-user-drag: none !important;
        -moz-user-drag: none !important;
        -o-user-drag: none !important;
        user-drag: none !important;
      }
      input, textarea {
        -webkit-user-select: auto !important;
        -moz-user-select: auto !important;
        -ms-user-select: auto !important;
        user-select: auto !important;
      }
    `;
    document.head.appendChild(style);

    return () => {
      document.removeEventListener('contextmenu', disableAll);
      document.removeEventListener('copy', disableAll);
      document.removeEventListener('cut', disableAll);
      document.removeEventListener('paste', disableAll);
      document.removeEventListener('keydown', disableAll);
      document.removeEventListener('selectstart', disableAll);
      document.removeEventListener('dragstart', disableAll);
      document.head.removeChild(style);
    };
  }, []);

  // Tab switch detection with auto-submit
  useEffect(() => {
    const handleVisibilityChange = () => {
      if (document.hidden && !submitting && !loading) {
        setTabSwitchCount(prev => {
          const newCount = prev + 1;

          if (newCount === 1) {
            alert('⚠️ Warning: Tab switching is not allowed. One more violation will end your quiz.');
          }

          if (newCount >= 2) {
            alert('❌ Quiz ended due to tab switching violation. Submitting your answers...');
            setTimeout(() => handleSubmitQuiz(), 500);
          }

          return newCount;
        });
      }
    };

    document.addEventListener('visibilitychange', handleVisibilityChange);
    return () => document.removeEventListener('visibilitychange', handleVisibilityChange);
  }, [submitting, loading]);

  // Prevent back navigation
  useEffect(() => {
    window.history.pushState(null, null, window.location.href);
    const handlePopState = () => {
      window.history.pushState(null, null, window.location.href);
      alert('⛔ Navigation is disabled during quiz');
    };

    window.addEventListener('popstate', handlePopState);
    return () => window.removeEventListener('popstate', handlePopState);
  }, []);

  // Fetch questions
  useEffect(() => {
    const fetchQuestions = async () => {
      try {
        setLoading(true);
        const response = await axios.get(`http://localhost:8000/questions/${quizId}`);
        if (response.data && response.data.questions) {
          setQuestions(response.data.questions);
          // Initialize answers object with empty values
          const initialAnswers = {};
          response.data.questions.forEach(q => {
            initialAnswers[q.id] = null;
          });
          setAnswers(initialAnswers);
          setCurrentIndex(0);
        } else {
          setError('Invalid response from server');
        }
      } catch (err) {
        console.error('Fetch error:', err);
        setError('Failed to load questions. Please check if backend is running.');
      } finally {
        setLoading(false);
      }
    };

    if (quizId) {
      fetchQuestions();
    } else {
      setError('No quiz ID provided');
      setLoading(false);
    }
  }, [quizId]);

  const handleSubmitQuiz = useCallback(async () => {
    if (submitting) return;

    // Filter out null values (unanswered questions)
    const answeredQuestions = Object.entries(answers).filter(([_, value]) => value !== null);

    if (answeredQuestions.length !== questions.length) {
      alert(`Please answer all questions. You have answered ${answeredQuestions.length} out of ${questions.length} questions.`);
      return;
    }

    setSubmitting(true);

    try {
      const answersList = answeredQuestions.map(([qId, selected]) => ({
        question_id: parseInt(qId),
        selected_option: selected
      }));

      console.log('Submitting answers:', answersList);

      const response = await axios.post('http://localhost:8000/submit', {
        quiz_id: quizId,
        answers: answersList,
        tab_switch_count: tabSwitchCount
      });

      console.log('Submission response:', response.data);

      if (response.data && response.data.score !== undefined) {
        onSubmit({
          score: response.data.score,
          totalQuestions: response.data.total_questions,
          timeTaken: response.data.time_taken_microseconds
        });
      } else {
        throw new Error('Invalid response format');
      }

    } catch (err) {
      console.error('Submission error:', err);

      let errorMessage = 'Failed to submit. ';

      if (err.response) {
        // The request was made and the server responded with a status code
        // that falls out of the range of 2xx
        console.error('Error response data:', err.response.data);
        console.error('Error response status:', err.response.status);

        if (err.response.data && err.response.data.detail) {
          errorMessage += err.response.data.detail;
        } else if (err.response.status === 500) {
          errorMessage += 'Internal server error. Please contact support.';
        } else {
          errorMessage += `Server error (${err.response.status})`;
        }
      } else if (err.request) {
        // The request was made but no response was received
        errorMessage += 'Cannot connect to server. Please check if backend is running.';
      } else {
        // Something happened in setting up the request that triggered an Error
        errorMessage += err.message;
      }

      alert(errorMessage);
      setSubmitting(false);
    }
  }, [quizId, answers, tabSwitchCount, onSubmit, submitting, questions.length]);

  const handleAnswerSelect = (questionId, option) => {
    if (submitting) return;

    setAnswers(prev => ({
      ...prev,
      [questionId]: option
    }));

    // Don't auto-advance if we're on the last question
    if (currentIndex < questions.length - 1) {
      setTimeout(() => {
        setCurrentIndex(prev => prev + 1);
      }, 300);
    }
  };

  const goToQuestion = (index) => {
    if (index >= 0 && index < questions.length) {
      setCurrentIndex(index);
    }
  };

  const handleSubmit = () => {
    handleSubmitQuiz();
  };

  const handleTimeUp = () => {
    if (!submitting) {
      const answeredCount = Object.values(answers).filter(v => v !== null).length;
      if (answeredCount > 0) {
        alert('⏰ Time is up! Submitting your answers...');
        handleSubmitQuiz();
        if (onTimeout) onTimeout();
      }
    }
  };

  // Loading state
  if (loading) {
    return (
      <div style={{
        height: '100vh',
        display: 'flex',
        alignItems: 'center',
        justifyContent: 'center',
        backgroundColor: '#ffffff',
        color: '#333333',
        fontSize: '18px'
      }}>
        Loading questions...
      </div>
    );
  }

  // Error state
  if (error) {
    return (
      <div style={{
        height: '100vh',
        display: 'flex',
        alignItems: 'center',
        justifyContent: 'center',
        backgroundColor: '#ffffff'
      }}>
        <div style={{ textAlign: 'center', padding: '20px' }}>
          <p style={{ color: '#ff0000', marginBottom: '20px', fontSize: '16px' }}>{error}</p>
          <button 
            onClick={() => window.location.reload()}
            style={{
              padding: '10px 24px',
              backgroundColor: '#000000',
              color: '#ffffff',
              border: 'none',
              borderRadius: '4px',
              fontSize: '15px',
              cursor: 'pointer'
            }}
          >
            Retry
          </button>
        </div>
      </div>
    );
  }

  if (!questions || questions.length === 0) {
    return (
      <div style={{
        height: '100vh',
        display: 'flex',
        alignItems: 'center',
        justifyContent: 'center',
        backgroundColor: '#ffffff'
      }}>
        <div style={{ textAlign: 'center' }}>
          <p style={{ color: '#333333', marginBottom: '20px' }}>No questions available</p>
          <button 
            onClick={() => window.location.reload()}
            style={{
              padding: '10px 24px',
              backgroundColor: '#000000',
              color: '#ffffff',
              border: 'none',
              borderRadius: '4px',
              cursor: 'pointer'
            }}
          >
            Retry
          </button>
        </div>
      </div>
    );
  }

  const currentQuestion = questions[currentIndex];

  if (!currentQuestion) {
    return (
      <div style={{
        height: '100vh',
        display: 'flex',
        alignItems: 'center',
        justifyContent: 'center',
        backgroundColor: '#ffffff'
      }}>
        <div style={{ textAlign: 'center' }}>
          <p style={{ color: '#ff0000', marginBottom: '20px' }}>Error loading question</p>
          <button 
            onClick={() => window.location.reload()}
            style={{
              padding: '10px 24px',
              backgroundColor: '#000000',
              color: '#ffffff',
              border: 'none',
              borderRadius: '4px',
              cursor: 'pointer'
            }}
          >
            Reload
          </button>
        </div>
      </div>
    );
  }

  const answeredCount = Object.values(answers).filter(v => v !== null).length;
  const remainingCount = questions.length - answeredCount;
  const allAnswered = answeredCount === questions.length;

  return (
    <div style={{
      minHeight: '100vh',
      backgroundColor: '#ffffff',
      display: 'flex',
      flexDirection: 'column',
      alignItems: 'center',
      position: 'relative'
    }}>
      {/* Overlay to prevent screenshots on some devices (optional) */}
      <div style={{
        position: 'fixed',
        top: 0,
        left: 0,
        right: 0,
        bottom: 0,
        backgroundColor: 'transparent',
        zIndex: 9999,
        pointerEvents: 'none'
      }} />

      <div style={{
        width: '100%',
        maxWidth: '700px',
        padding: '40px 20px',
        position: 'relative',
        zIndex: 1
      }}>
        {/* Header */}
        <div style={{
          display: 'flex',
          justifyContent: 'space-between',
          alignItems: 'center',
          marginBottom: '20px',
          paddingBottom: '15px',
          borderBottom: '1px solid #e5e5e5'
        }}>
          <div style={{ 
            fontSize: '18px',
            fontWeight: '500',
            color: '#333333'
          }}>
            Question {currentIndex + 1} of {questions.length}
          </div>
          <Timer 
            initialSeconds={1800}
            onTimeUp={handleTimeUp}
            isActive={!submitting}
          />
        </div>

        {/* Question navigation dots */}
        <div style={{
          display: 'flex',
          gap: '8px',
          marginBottom: '30px',
          flexWrap: 'wrap',
          justifyContent: 'center'
        }}>
          {questions.map((q, idx) => {
            const isAnswered = answers[q.id] !== null;
            const isCurrent = idx === currentIndex;

            return (
              <div
                key={q.id}
                onClick={() => goToQuestion(idx)}
                style={{
                  width: '32px',
                  height: '32px',
                  borderRadius: '16px',
                  backgroundColor: isAnswered ? '#000000' : '#e0e0e0',
                  border: isCurrent ? '3px solid #ff0000' : 'none',
                  display: 'flex',
                  alignItems: 'center',
                  justifyContent: 'center',
                  color: isAnswered ? '#ffffff' : '#666666',
                  fontSize: '13px',
                  fontWeight: '600',
                  cursor: 'pointer',
                  transition: 'all 0.2s'
                }}
              >
                {idx + 1}
              </div>
            );
          })}
        </div>

        {/* Warning */}
        {tabSwitchCount === 1 && (
          <div style={{
            backgroundColor: '#fff3cd',
            color: '#856404',
            padding: '12px 16px',
            marginBottom: '30px',
            fontSize: '14px',
            borderRadius: '4px'
          }}>
            ⚠️ Warning: Tab switching detected (1/2). Next violation will end your quiz.
          </div>
        )}

        {/* Question */}
        <div style={{ marginBottom: '40px' }}>
          <h2 style={{
            fontSize: '22px',
            fontWeight: '500',
            lineHeight: '1.6',
            marginBottom: '30px',
            color: '#000000'
          }}>
            {currentQuestion.question}
          </h2>

          {/* Options */}
          <div>
            {currentQuestion.options && currentQuestion.options.map((option, idx) => {
              const isSelected = answers[currentQuestion.id] === option;
              const optionId = `opt_${currentQuestion.id}_${idx}`;

              return (
                <div
                  key={idx}
                  onClick={() => !submitting && handleAnswerSelect(currentQuestion.id, option)}
                  style={{
                    display: 'flex',
                    alignItems: 'center',
                    marginBottom: '16px',
                    cursor: submitting ? 'default' : 'pointer',
                    padding: '12px 16px',
                    backgroundColor: isSelected ? '#f0f0f0' : 'transparent',
                    borderRadius: '8px',
                    border: isSelected ? '2px solid #000000' : '1px solid #e0e0e0',
                    transition: 'all 0.2s'
                  }}
                >
                  <input
                    type="radio"
                    id={optionId}
                    name={`q_${currentQuestion.id}`}
                    checked={isSelected}
                    onChange={() => {}}
                    disabled={submitting}
                    style={{
                      width: '20px',
                      height: '20px',
                      marginRight: '15px',
                      cursor: submitting ? 'default' : 'pointer',
                      accentColor: '#000000'
                    }}
                  />
                  <label
                    htmlFor={optionId}
                    style={{
                      fontSize: '16px',
                      cursor: submitting ? 'default' : 'pointer',
                      color: '#333333',
                      fontWeight: isSelected ? '600' : '400'
                    }}
                  >
                    {option}
                  </label>
                </div>
              );
            })}
          </div>
        </div>

        {/* Progress indicator */}
        <div style={{
          marginBottom: '25px',
          padding: '15px',
          backgroundColor: '#f8f8f8',
          borderRadius: '8px'
        }}>
          <div style={{
            display: 'flex',
            justifyContent: 'space-between',
            alignItems: 'center',
            marginBottom: '10px'
          }}>
            <span style={{ fontSize: '15px', color: '#333333', fontWeight: '500' }}>
              Progress: {answeredCount}/{questions.length} questions answered
            </span>
            <span style={{ 
              fontSize: '15px', 
              color: remainingCount === 0 ? '#00aa00' : '#ff0000',
              fontWeight: '600'
            }}>
              {remainingCount === 0 ? '✓ COMPLETE' : `${remainingCount} remaining`}
            </span>
          </div>

          <div style={{
            width: '100%',
            height: '8px',
            backgroundColor: '#e0e0e0',
            borderRadius: '4px',
            overflow: 'hidden'
          }}>
            <div style={{
              width: `${(answeredCount / questions.length) * 100}%`,
              height: '100%',
              backgroundColor: remainingCount === 0 ? '#00aa00' : '#000000',
              transition: 'width 0.3s ease'
            }} />
          </div>
        </div>

        {/* Submit button */}
        <button
          onClick={handleSubmit}
          disabled={!allAnswered || submitting}
          style={{
            width: '100%',
            backgroundColor: !allAnswered ? '#cccccc' : (submitting ? '#999999' : '#000000'),
            color: '#ffffff',
            border: 'none',
            padding: '18px 0',
            borderRadius: '8px',
            fontSize: '18px',
            fontWeight: '600',
            cursor: (!allAnswered || submitting) ? 'not-allowed' : 'pointer',
            opacity: (!allAnswered || submitting) ? 0.7 : 1,
            transition: 'all 0.2s',
            letterSpacing: '1px'
          }}
        >
          {submitting ? 'SUBMITTING...' : 'SUBMIT QUIZ'}
        </button>

        {submitting && (
          <div style={{ 
            textAlign: 'center', 
            marginTop: '15px', 
            color: '#666666', 
            fontSize: '14px' 
          }}>
            Please wait while we submit your answers...
          </div>
        )}
      </div>
    </div>
  );
};

export default QuizPage;
